INSERT INTO content_translations (resource_type, resource_key, lang, text, updated_at) VALUES
('about_me_question', 'question1', 'ta', 'உங்கள் குடும்பத்தில், பயம் அல்லது தயக்கம் இல்லாமல் உங்கள் கருத்துகளை யாருடன் சுதந்திரமாக பகிர்ந்து கொள்ள முடியும்?', NOW()),
('about_me_question', 'question2', 'ta', 'உங்கள் குடும்பத்தினரைத் தவிர, பயம் அல்லது தயக்கம் இல்லாமல் உங்கள் கருத்துகளையும் உணர்வுகளையும் யாருடன் சுதந்திரமாக பகிர்ந்து கொள்ள முடியும்?', NOW()),
('about_me_question', 'question3', 'ta', 'வீட்டில் நீங்கள் செய்யும் வேலைகள் என்னென்ன? (உதா: விவசாயப் பணிகளில் உதவுதல், கடையிலிருந்து காய்கறிகள் மற்றும் மளிகைப் பொருட்கள் வாங்கி வருதல், பணம் தொடர்பான வேலைகள், விலங்குகளை பராமரித்தல், தண்ணீர் நிரப்புதல் போன்றவை)', NOW()),
('about_me_question', 'question4', 'ta', 'நீங்கள் விரும்பி செய்யும் வேலைகள்: a. பள்ளி நேரத்தில் b. பள்ளி நேரத்திற்கு பிறகு (பள்ளி தொடங்குவதற்கு முன் மற்றும் பள்ளி முடிந்த பிறகு)', NOW()),
('about_me_question', 'question5', 'ta', 'நீங்கள் சுயமாக செய்ய விரும்பும் வேலைகள் என்னென்ன? (தனியாகவே செய்து முடிக்கும் பணிகள்)', NOW()),
('about_me_question', 'question6', 'ta', 'நீங்கள் குழுவாக அல்லது உங்கள் நண்பர்களுடன் செய்ய விரும்பும் செயல்கள் என்னென்ன?', NOW()),
('about_me_question', 'question7', 'ta', 'பள்ளியில் உங்களுக்கு கடினமாக தோன்றும் செயல்கள் என்னென்ன? எழுதுங்கள்.', NOW()),
('about_me_question', 'question8', 'ta', 'பள்ளி வேலைகள் / செயல்களைத் தவிர, உங்களுக்கு கடினமாக இருக்கும் மற்ற வேலைகள் என்னென்ன?', NOW()),
('about_me_question', 'question9', 'ta', 'நீங்கள் தனியாக செய்ய விரும்பும் செயல்கள் என்னென்ன? உதாரணமாக, படித்தல், வரைதல், விளையாடல், போன்றவை.', NOW()),
('about_me_question', 'question10', 'ta', 'நீங்கள் விரும்பும் அல்லது விரும்பாத செயல்களை தனியாக செய்ய விரும்புகிறீர்களா?', NOW()),
('about_me_question', 'question11', 'ta', '', NOW()), -- Hidden for Tamil (19 unique questions logic)
('about_me_question', 'question12', 'ta', 'உங்களைப் பற்றி நீங்கள் என்ன சொல்ல விரும்புகிறீர்கள்? உங்களிடம் உள்ள நல்ல குணங்கள் என்ன?', NOW()), -- Matches User Q11
('about_me_question', 'question13', 'ta', 'உங்களிடம் உள்ள எந்த குணங்களை பெற்றோர், ஆசிரியர்கள் மற்றும் நண்பர்கள் போன்றோர் விரும்புகிறார்கள் என்று நீங்கள் நினைக்கிறீர்கள்? பட்டியலிடுங்கள். (பெற்றோர், ஆசிரியர்கள், நண்பர்களிடம் கேட்டு உறுதிப்படுத்துங்கள்.)', NOW()),
('about_me_question', 'question14', 'ta', 'உங்களிடம் உள்ள எந்த பழக்கம் அல்லது நடத்தைையை நீங்கள் மேம்படுத்த அல்லது மாற்ற விரும்புகிறீர்கள்?', NOW()),
('about_me_question', 'question15', 'ta', 'உங்களின் எந்த குணம் அல்லது நடத்தையை மற்றவர்கள் திருத்த வேண்டும் என்று விரும்புகிறார்கள் அல்லது ஆலோசனை தருகிறார்கள்?', NOW()),
('about_me_question', 'question16', 'ta', 'எதிர்காலத்தில் நீங்கள் ஏதாவது ஆக அல்லது யாராவது ஆக வாய்ப்பு இருந்தால், நீங்கள் என்ன ஆக விரும்புகிறீர்கள்?', NOW()),
('about_me_question', 'question17', 'ta', 'உங்களைப் பற்றி நீங்கள் பெற்ற நேர்காணல் அல்லது கருத்தை நினைவில் கொள்ளுங்கள். உங்கள் எந்த செயல் அல்லது வேலைக்கு பாராட்டு கிடைத்தது? அதை நீங்கள் எவ்வாறு சாதித்தீர்கள்? சுருக்கமாக விளக்குங்கள்.', NOW()),
('about_me_question', 'question18', 'ta', 'நீங்கள் சமீபத்தில் எதிர்கொண்ட ஒரு கடினமான அல்லது சவாலான சூழ்நிலையை பற்றி யோசியுங்கள். அதை நீங்கள் எவ்வாறு எதிர்கொண்டீர்கள் அல்லது அதிலிருந்து எவ்வாறு மீண்டீர்கள்? அதிலிருந்து நீங்கள் கற்றுக்கொண்ட பாடம் என்ன?', NOW()),
('about_me_question', 'question19', 'ta', 'மற்றவர்கள் உங்களை தவறாக புரிந்து கொண்ட அல்லது உங்களைப் பற்றி தவறான கருத்து கொண்ட ஒரு சூழ்நிலையை நினைவில் கொள்ளுங்கள். அந்த சூழ்நிலையை நீங்கள் எவ்வாறு கையாண்டிர்கள், அதிலிருந்து நீங்கள் என்ன கற்றுக்கொண்டீர்கள்?', NOW()),
('about_me_question', 'question20', 'ta', 'சுருக்கத்தின் அடிப்படையில், உங்களைப் பற்றி சுருக்கமாக எழுதுங்கள். (சொற்கள், படங்கள் அல்லது குறிகளை பயன்படுத்தலாம்.)', NOW())
INSERT INTO content_translations (resource_type, resource_key, lang, text, updated_at) VALUES
('about_me_help', 'question1', 'ta', 'நீங்கள் பாதுகாப்பாக பேச முடியும் என்ற குடும்ப உறுப்பினரை தேர்வு செய்யவும்.', NOW()),
('about_me_help', 'question2', 'ta', 'உங்கள் குடும்பத்திற்கு வெளியே, நீங்கள் நம்பி நிம்மதியாக பேச முடியும் நபரை நினைத்துப் பதிலளிக்கவும்.', NOW()),
('about_me_help', 'question3', 'ta', 'வீட்டில் நீங்கள் தினமும் செய்யும் வேலைகளை நினைத்து பதிலளிக்கவும்.', NOW()),
('about_me_help', 'question4', 'ta', 'பள்ளி நேரத்திலும் , பள்ளிக்குப் பிறகும் நீங்கள் விரும்பி செய்யும் செயல்களை எழுதுங்கள்.', NOW()),
('about_me_help', 'question5', 'ta', 'நீங்கள் தனியாக செய்து மகிழும் செயல்களை நினைத்து பதிலளிக்கவும்.', NOW()),
('about_me_help', 'question6', 'ta', 'நண்பர்களுடன் சேர்ந்து செய்ய விரும்பும் செயல்களை நினைத்து பதிலளிக்கவும்.', NOW()),
('about_me_help', 'question7', 'ta', 'பள்ளியில் உங்களுக்கு கடினமாக இருக்கும் செயல்களை நினைத்து பதிலளிக்கவும்.', NOW()),
('about_me_help', 'question8', 'ta', 'பள்ளிக்கு வெளியே உங்களுக்கு கடினமாக இருக்கும் வேலைகளை நினைத்து பதிலளிக்கவும்.', NOW()),
('about_me_help', 'question9', 'ta', 'நீங்கள் தனியாக செய்து மகிழும் செயல்களை நினைத்து பதிலளிக்கவும்.', NOW()),
('about_me_help', 'question10', 'ta', 'செயல்களை தனியாக செய்ய விரும்புகிறீர்களா என நினைத்து பதிலளிக்கவும்.', NOW()),
('about_me_help', 'question11', 'ta', '', NOW()), -- Hidden
('about_me_help', 'question12', 'ta', 'உங்களிடம் உள்ள நல்ல குணங்கள் என்ன?', NOW()), -- Matches User Help 11
('about_me_help', 'question13', 'ta', 'பெற்றோர், ஆசிரியர்கள், நண்பர்கள் உங்களில் விரும்பும் நல்ல குணங்கள் என்ன?', NOW()),
('about_me_help', 'question14', 'ta', 'நீங்கள் மாற்ற அல்லது மேம்படுத்த விரும்பும் பழக்கம் அல்லது நடத்தை ஏதாவது உள்ளதா?', NOW()),
('about_me_help', 'question15', 'ta', 'நீங்கள் திருத்த வேண்டும் என்று அவர்கள் கூறும் குணம் அல்லது நடத்தை எது?', NOW()),
('about_me_help', 'question16', 'ta', 'நீங்கள் ஏதாவது ஆக அல்லது யாராவது ஆக வாய்ப்பு இருந்தால், என்ன ஆக விரும்புகிறீர்கள்?', NOW()),
('about_me_help', 'question17', 'ta', 'எந்த வேலை அல்லது செயலில் உங்களுக்கு பாராட்டு கிடைத்தது?', NOW()),
('about_me_help', 'question18', 'ta', 'சமீபத்தில் நீங்கள் எதிர்கொண்ட ஒரு சிக்கல் அல்லது சவாலை நினைத்து பாருங்கள்', NOW()),
('about_me_help', 'question19', 'ta', 'யாராவது உங்களை தவறாக புரிந்துகொண்ட ஒரு நேரத்தை நினைத்து பாருங்கள்', NOW()),
('about_me_help', 'question20', 'ta', 'சுருக்கத்தை வைத்து உங்களைப் பற்றி சுருக்கமாக எழுதுங்கள்.', NOW())
