-- Migration: Update Tamil About Me Questions and Help Text
-- Updates the Tamil translations for 'about_me_question' and 'about_me_help' resource types.

-- Questions

ON CONFLICT (resource_type, resource_key, lang) 
DO UPDATE SET 
    text = EXCLUDED.text,
    updated_at = NOW();

-- Help Text

ON CONFLICT (resource_type, resource_key, lang) 
DO UPDATE SET 
    text = EXCLUDED.text,
    updated_at = NOW();
